class Solution:
    def isValid(self, board: List[List[int]]) -> bool:
        # Check each row and column
        for i in range(9):
            row = board[i]
            col = [board[j][i] for j in range(9)]
            if len(set(row + col)) != 9:
                return False

        # Check each 3x3 sub-grid
        for i in range(0, 9, 3):
            for j in range(0, 9, 3):
                grid = [board[x][y] for x in range(i, i+3) for y in range(j, j+3)]
                if len(set(grid)) != 9:
                    return False

        return True

