bool Solution::isValid(vector<vector<int>>& board) { 
  // Check each row and column 
  for (int i = 0; i < 9; i++) { 
    for (int j = 0; j < 9; j++) { 
      if (!isValidRow(board[i]) || !isValidCol(board[i], j) || !isValidGrid(board, i, j)) return false; 
    } 
  } 
  return true; 

bool isValidRow(const vector<int>& row) {
  int count[10] = {0};
  for (int i = 0; i < 9; i++) count[row[i]]++;
  for (int i = 1; i <= 9; i++) if (count[i] != 1) return false;
  return true;
} 
bool isValidCol(const vector<int>& row, int j) {
  int count[10] = {0};
  for (int i = 0; i < 9; i++) count[row[i]]++;
  for (int i = 1; i <= 9; i++) if (count[i] != 1) return false;
  return true;
} 
bool isValidGrid(const vector<vector<int>>& board, int i, int j) {
  int count[10] = {0};
  for (int x = (i / 3) * 3; x < (i / 3 + 1) * 3; x++) 
    for (int y = (j / 3) * 3; y < (j / 3 + 1) * 3; y++) count[board[x][y]]++;
  for (int i = 1; i <= 9; i++) if (count[i] != 1) return false;
  return true;
}
